const body = $input.first().json.body || $input.first().json;
const { action, username, password, filename, content, manifest } = body;
const server = (body.server || 'nuage.apps.education.fr').replace(/^https?:\/\//, '').replace(/\/$/, '');

if (!username || !password) {
  return [{ json: { success: false, error: 'Identifiants manquants' } }];
}

const baseUrl = `https://${server}/remote.php/dav/files/${encodeURIComponent(username)}/mentoria/`;
const manifestUrl = baseUrl + 'manifest.json';
const auth = 'Basic ' + Buffer.from(`${username}:${password}`).toString('base64');

const doGet = async (url, extraHeaders = {}) => {
  return await this.helpers.httpRequest({
    method: 'GET', url,
    headers: { 'Authorization': auth, ...extraHeaders },
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  });
};

const tryParseManifest = (r) => {
  if (r.statusCode !== 200) return null;
  try {
    const parsed = typeof r.body === 'string' ? JSON.parse(r.body) : r.body;
    return Array.isArray(parsed) ? parsed : null;
  } catch { return null; }
};

try {

  // ── TEST ──
  if (action === 'test') {
    const debug = { server };
    const ocsRes = await doGet(`https://${server}/ocs/v1.php/cloud/user?format=json`, { 'OCS-APIREQUEST': 'true' });
    debug.ocs_status = ocsRes.statusCode;
    if (ocsRes.statusCode === 401 || ocsRes.statusCode === 403) {
      return [{ json: { success: false, error: "Identifiants invalides — vérifiez votre mot de passe d'application.", debug } }];
    }
    if (ocsRes.statusCode !== 200) {
      return [{ json: { success: false, error: 'Erreur OCS: ' + ocsRes.statusCode, debug } }];
    }
    const getRes = await doGet(manifestUrl);
    debug.get_manifest_status = getRes.statusCode;
    debug.get_manifest_body = (typeof getRes.body === 'string' ? getRes.body : JSON.stringify(getRes.body)).substring(0, 80);
    debug.manifest_valid = tryParseManifest(getRes) !== null;
    return [{ json: { success: true, action: 'test', debug } }];
  }

  // ── LIST ──
  if (action === 'list') {
    const r = await doGet(manifestUrl);
    const manifest = tryParseManifest(r) || [];
    return [{ json: { success: true, files: manifest.map(n => ({ name: n })) } }];
  }

  // ── READ ──
  if (action === 'read') {
    if (!filename) return [{ json: { success: false, error: 'Nom de fichier manquant' } }];
    const r = await doGet(baseUrl + encodeURIComponent(filename));
    if (r.statusCode === 404) return [{ json: { success: false, error: 'Fichier introuvable' } }];
    if (r.statusCode === 401) return [{ json: { success: false, error: 'Session expirée — reconnectez-vous' } }];
    if (r.statusCode >= 400) return [{ json: { success: false, error: 'Erreur lecture (code ' + r.statusCode + ')' } }];
    try {
      const parsed = typeof r.body === 'string' ? JSON.parse(r.body) : r.body;
      return [{ json: { success: true, content: parsed } }];
    } catch(e) {
      return [{ json: { success: false, error: 'Fichier corrompu : ' + e.message } }];
    }
  }

  // ── WRITE — prépare le PUT (exécuté par les nœuds HTTP natifs suivants) ──
  if (action === 'write') {
    if (!filename) return [{ json: { success: false, error: 'Nom de fichier manquant' } }];
    const fileContent = typeof content === 'string' ? content : JSON.stringify(content, null, 2);
    return [{ json: {
      _op: 'write',
      authHeader: auth,
      putUrl: baseUrl + encodeURIComponent(filename),
      manifestUrl,
      filename,
      fileContent,
      manifest: Array.isArray(manifest) ? manifest : null
    } }];
  }

  // ── DELETE — prépare le DELETE (exécuté par les nœuds HTTP natifs suivants) ──
  if (action === 'delete') {
    if (!filename) return [{ json: { success: false, error: 'Nom de fichier manquant' } }];
    return [{ json: {
      _op: 'delete',
      authHeader: auth,
      deleteUrl: baseUrl + encodeURIComponent(filename),
      manifestUrl,
      filename
    } }];
  }

  // ── FETCH URL ──
  if (action === 'fetch_url') {
    if (!body.url) return [{ json: { success: false, error: 'URL manquante' } }];
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url: body.url,
      headers: { 'User-Agent': 'Mozilla/5.0 (compatible; Mentoria/2.7)' },
      returnFullResponse: true,
      ignoreHttpStatusErrors: true
    });
    if (res.statusCode >= 400) return [{ json: { success: false, error: 'Impossible de récupérer la page (code ' + res.statusCode + ')' } }];
    const html = typeof res.body === 'string' ? res.body : JSON.stringify(res.body);
    // Extraction texte : supprime balises, scripts, styles
    const text = html
      .replace(/<script[\s\S]*?<\/script>/gi, '')
      .replace(/<style[\s\S]*?<\/style>/gi, '')
      .replace(/<[^>]+>/g, ' ')
      .replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
      .replace(/\s{2,}/g, ' ').trim()
      .substring(0, 50000);
    return [{ json: { success: true, text } }];
  }

  return [{ json: { success: false, error: 'Action inconnue : ' + action } }];

} catch(e) {
  return [{ json: { success: false, error: e.message } }];
}

const putResult = $('HTTP PUT Fichier').first().json;
const prep = $('Code Préparer').first().json;

if (putResult.statusCode === 404 || putResult.statusCode === 409) {
  return [{ json: { success: false, error: 'Dossier mentoria introuvable. Reconnectez-vous.' } }];
}
if (putResult.statusCode === 401) {
  return [{ json: { success: false, error: 'Session expirée — reconnectez-vous' } }];
}
if (putResult.statusCode >= 400) {
  return [{ json: { success: false, error: 'Erreur écriture (code ' + putResult.statusCode + ')' } }];
}

// Le client envoie la liste complète des fichiers — plus fiable que de lire le manifest depuis le Nuage
let manifest = Array.isArray(prep.manifest) ? prep.manifest : [prep.filename];
if (!manifest.includes(prep.filename)) manifest.push(prep.filename);

return [{ json: {
  _writeOk: true,
  authHeader: prep.authHeader,
  manifestUrl: prep.manifestUrl,
  updatedManifest: JSON.stringify(manifest)
} }];

const r = $input.first().json;
const manifestData = $('Code Mise à jour Manifest').first().json;
if (r.statusCode && r.statusCode >= 400) {
  return [{ json: { success: false, error: 'Erreur sauvegarde manifest (code ' + r.statusCode + ')', debug: manifestData.debug } }];
}
return [{ json: { success: true, action: 'write', debug: manifestData.debug } }];

const getResult = $input.first().json;
const prep = $('Code Préparer').first().json;

let manifest = [];
if (getResult.statusCode === 200) {
  try {
    const parsed = typeof getResult.body === 'string' ? JSON.parse(getResult.body) : getResult.body;
    if (Array.isArray(parsed)) manifest = parsed;
  } catch(e) {}
}

return [{ json: {
  authHeader: prep.authHeader,
  manifestUrl: prep.manifestUrl,
  updatedManifest: JSON.stringify(manifest.filter(n => n !== prep.filename))
} }];
